import pytest
import math

# Helper functions for testing
def add_one(x):
    return x + 1

def double(x):
    return x * 2

def square(x):
    return x * x

def to_string(x):
    return str(x)

def is_positive(x):
    return x > 0

def raise_value_error(x):
    raise ValueError("Test error")

def identity(x):
    return x

def add_prefix(prefix):
    def inner(x):
        return prefix + str(x)
    return inner

def add_suffix(suffix):
    def inner(x):
        return str(x) + suffix
    return inner


