        """Test composition with a single function"""
        fn = compose(add_one)
        assert fn(5) == 6
        assert fn(0) == 1
        assert fn(-3) == -2

    def test_two_functions(self):
        """Test composition with two functions"""
        # add_one then double
        fn = compose(double, add_one)
        assert fn(5) == 12  # (5 + 1) * 2 = 12

        # double then add_one
        fn = compose(add_one, double)
        assert fn(5) == 11  # (5 * 2) + 1 = 11

    def test_three_functions(self):
        """Test composition with three functions"""
        # square -> add_one -> double
        fn = compose(double, add_one, square)
        assert fn(3) == 20  # (3² + 1) * 2 = 20
        assert fn(0) == 2   # (0² + 1) * 2 = 2

    def test_mixed_function_types(self):
