        fn = compose(to_string, add_one, double)
        result = fn(5)
        assert result == "11"  # (5 * 2) + 1 = 11, then string
        assert isinstance(result, str)

    def test_identity_composition(self):
        """Test that identity function doesn't change behavior"""
        fn = compose(identity, add_one, identity)
        assert fn(5) == 6

        fn = compose(add_one)
        assert fn(5) == 6

    def test_boolean_function(self):
        """Test composition with boolean-returning function"""
        fn = compose(is_positive, add_one)
        assert fn(0) == True   # 0 + 1 > 0
        assert fn(-2) == False # -2 + 1 > 0

    def test_higher_order_functions(self):
        """Test composition with functions that return functions"""
        fn = compose(add_suffix("!"), add_prefix("Value: "))
        result = fn(42)
        assert result == "Value: 42!"

    def test_empty_composition(self):
        """Test composition with no functions (should return identity)"""
        fn = compose()
